#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding orthopedic-assessment (19 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    first_name:string! \
    last_name:string! \
    date_of_birth:date \
    sex:string! \
    phone:string! \
    email:string! \
    address:text! \
    occupation:string! \
    dominant_hand:string! \
    sport_activity_level:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    primary_complaint:text! \
    affected_region:string! \
    affected_side:string! \
    onset_type:string! \
    onset_date:date \
    mechanism_of_injury:text! \
    duration:text! \
    aggravating_factors:text! \
    relieving_factors:text! \
    previous_episodes:string! \
    previous_episode_details:text! \
    work_related:string! \
    sport_related:string! \
    chief_complaint_notes:text! \
    --htmx

cargo loco generate scaffold assessment_pain_assessment \
    assessment:references \
    pain_at_rest:int \
    pain_with_activity:int \
    pain_at_night:int \
    worst_pain:int \
    pain_character:string! \
    pain_pattern:string! \
    pain_location:text! \
    pain_radiation:text! \
    night_waking:string! \
    morning_stiffness:string! \
    morning_stiffness_duration_minutes:int \
    current_analgesia:text! \
    analgesia_effectiveness:string! \
    pain_notes:text! \
    --htmx

cargo loco generate scaffold assessment_dash_questionnaire \
    assessment:references \
    q01_open_jar:int \
    q02_write:int \
    q03_turn_key:int \
    q04_prepare_meal:int \
    q05_push_door:int \
    q06_place_object_shelf:int \
    q07_heavy_household:int \
    q08_garden_yard:int \
    q09_make_bed:int \
    q10_carry_bag:int \
    q11_carry_heavy:int \
    q12_overhead:int \
    q13_wash_back:int \
    q14_use_knife:int \
    q15_recreational_force:int \
    q16_recreational_arm:int \
    q17_transportation:int \
    q18_sexual_activity:int \
    q19_family_care:int \
    q20_social_activity:int \
    q21_limited_work:int \
    q22_usual_work:int \
    q23_arm_pain:int \
    q24_arm_pain_activity:int \
    q25_tingling:int \
    q26_weakness:int \
    q27_stiffness:int \
    q28_sleep_difficulty:int \
    q29_less_capable:int \
    q30_less_confident:int \
    items_answered:int \
    dash_score:double \
    dash_notes:text! \
    --htmx

cargo loco generate scaffold assessment_range_of_motion \
    assessment:references \
    joint_assessed:string! \
    side_assessed:string! \
    overall_rom_status:string! \
    range_of_motion_notes:text! \
    --htmx

cargo loco generate scaffold assessment_rom_measurement \
    range_of_motion:references \
    movement:string! \
    active_degrees:int \
    passive_degrees:int \
    normal_degrees:int \
    end_feel:string! \
    pain_on_movement:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_strength_testing \
    assessment:references \
    grip_strength_affected_kg:double \
    grip_strength_unaffected_kg:double \
    overall_strength_status:string! \
    strength_testing_notes:text! \
    --htmx

cargo loco generate scaffold assessment_strength_test_item \
    strength_testing:references \
    muscle_group:string! \
    movement:string! \
    mrc_grade:int \
    pain_on_testing:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_functional_limitations \
    assessment:references \
    dressing_difficulty:string! \
    washing_difficulty:string! \
    eating_difficulty:string! \
    work_difficulty:string! \
    household_difficulty:string! \
    lifting_difficulty:string! \
    sleep_difficulty:string! \
    recreation_difficulty:string! \
    driving_difficulty:string! \
    walking_difficulty:string! \
    stair_difficulty:string! \
    aids_in_use:text! \
    functional_limitations_notes:text! \
    --htmx

cargo loco generate scaffold assessment_imaging_history \
    assessment:references \
    has_previous_imaging:string! \
    imaging_requested:string! \
    imaging_requested_details:text! \
    imaging_notes:text! \
    --htmx

cargo loco generate scaffold assessment_imaging_item \
    imaging_history:references \
    modality:string! \
    body_region:string! \
    date_performed:date \
    findings:text! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_current_treatment \
    assessment:references \
    has_physiotherapy:string! \
    physiotherapy_details:text! \
    has_occupational_therapy:string! \
    occupational_therapy_details:text! \
    has_injection_therapy:string! \
    injection_details:text! \
    has_splinting_bracing:string! \
    splinting_bracing_details:text! \
    current_medications:text! \
    has_alternative_therapy:string! \
    alternative_therapy_details:text! \
    treatment_effectiveness:string! \
    current_treatment_notes:text! \
    --htmx

cargo loco generate scaffold assessment_surgical_history \
    assessment:references \
    has_previous_surgery:string! \
    surgery_considered:string! \
    surgery_considered_details:text! \
    patient_preference:string! \
    comorbidities_affecting_surgery:text! \
    anaesthetic_risk:string! \
    anticoagulant_use:string! \
    anticoagulant_details:text! \
    surgical_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_surgery_item \
    surgical_history:references \
    procedure_name:string! \
    date_performed:date \
    surgeon:string! \
    hospital:string! \
    outcome:string! \
    outcome_details:text! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    dash_score:double! \
    disability_category:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
